        .header { padding: 45px 20px 30px; text-align: center; background: #ffffff; }
        .logo { max-width: 170px; height: auto; margin-bottom: 10px; }
        .subtitle { color: #86868b; font-size: 13px; letter-spacing: 1px; text-transform: uppercase; font-weight: 600; }
        .content { padding: 0 40px 40px; color: #1d1d1f; }
        .greeting { font-size: 18px; font-weight: 600; margin-bottom: 8px; }
        .intro-text { color: #424245; font-size: 15px; line-height: 1.5; margin-bottom: 25px; }
        .invoice-card { background: #f5f5f7; border-radius: 16px; padding: 25px; margin-bottom: 30px; }
        .invoice-row { display: flex; justify-content: space-between; padding: 10px 0; border-bottom: 1px solid #e5e5e7; }
        .invoice-row:last-child { border-bottom: none; }
        .label { color: #86868b; font-size: 14px; }
        .value { font-weight: 600; color: #1d1d1f; text-align: right; }
        .total-amount { color: #0066cc; font-size: 20px; }
        .section-title { font-size: 16px; font-weight: 700; color: #1d1d1f; margin: 30px 0 15px; border-left: 4px solid #0066cc; padding-left: 12px; }
        .link-card { display: block; background: #ffffff; border: 1px solid #e5e5e7; border-radius: 12px; padding: 14px 18px; margin-bottom: 10px; text-decoration: none; color: #1d1d1f; font-weight: 500; transition: all 0.2s; }
        .link-card:hover { border-color: #0066cc; background: #fbfbfb; }
        .attachment-note { background: #eef7ff; border-radius: 10px; padding: 12px 18px; margin-top: 25px; display: flex; align-items: center; }
        .footer { background: #1d1d1f; padding: 30px; text-align: center; color: #86868b; font-size: 12px; }
        .footer strong { color: #ffffff; display: block; margin-bottom: 5px; }
    </style>
</head>
<body>
    <div class="wrapper">
        <div class="header">
            <img src="https://adamkom.com/wp-content/uploads/2026/01/logo-Adamkom-by-jjp-1.png" alt="Adamkom by JJP" class="logo">
